class Solution:
    def findBestValue(self, arr: List[int], target: int) -> int:
        arr.sort()
        total = sum(arr)
        if total <= target:
            return arr[-1]
        left, right = 0, arr[-1]
        while left <= right:
            mid = (left + right) // 2
            if sum(min(x, mid) for x in arr) <= target:
                right = mid - 1
            else:
                left = mid + 1
        return left

